/**
* Commits all changes to an index and closes all
* associated files.  Note that this may be a costly
* operation, so, try to re-use a single writer instead of
* closing and opening a new one.  See {@link #commit()} for
* caveats about write caching done by some IO devices.
*
* <p> If an Exception is hit during close, eg due to disk
* full or some other reason, then both the on-disk index
* and the internal state of the IndexWriter instance will
* be consistent.  However, the close will not be complete
* even though part of it (flushing buffered documents)
* may have succeeded, so the write lock will still be
* held.</p>
*
* <p> If you can correct the underlying cause (eg free up
* some disk space) then you can call close() again.
* Failing that, if you want to force the write lock to be
* released (dangerous, because you may then lose buffered
* docs in the IndexWriter instance) then you can do
* something like this:</p>
*
* <pre>
* try {
*   writer.close();
* } finally {
*   if (IndexWriter.isLocked(directory)) {
*     IndexWriter.unlock(directory);
*   }
* }
* </pre>
*
* after which, you must be certain not to use the writer
* instance anymore.</p>
*
* <p><b>NOTE</b>: if this method hits an OutOfMemoryError
* you should immediately close the writer, again.  See <a
* href="#OOME">above</a> for details.</p>
*
* @throws CorruptIndexException if the index is corrupt
* @throws IOException if there is a low-level IO error
*/
public void close() throws CorruptIndexException, IOException {
close(true);
}

/**
* Closes the index with or without waiting for currently
* running merges to finish.  This is only meaningful when
* using a MergeScheduler that runs merges in background
* threads.
*
* <p><b>NOTE</b>: if this method hits an OutOfMemoryError
* you should immediately close the writer, again.  See <a
* href="#OOME">above</a> for details.</p>
*
* <p><b>NOTE</b>: it is dangerous to always call
* close(false), especially when IndexWriter is not open
* for very long, because this can result in "merge
* starvation" whereby long merges will never have a
* chance to finish.  This will cause too many segments in
* your index over time.</p>
*
* @param waitForMerges if true, this call will block
* until all merges complete; else, it will ask all
* running merges to abort, wait until those merges have
* finished (which should be at most a few seconds), and
* then return.
*/
public void close(boolean waitForMerges) throws CorruptIndexException, IOException {

// Ensure that only one thread actually gets to do the closing:
if (shouldClose()) {
// If any methods have hit OutOfMemoryError, then abort
// on close, in case the internal state of IndexWriter
// or DocumentsWriter is corrupt
if (hitOOM)
rollbackInternal();
else
closeInternal(waitForMerges);
}
}

// Returns true if this thread should attempt to close, or
// false if IndexWriter is now closed; else, waits until
// another thread finishes closing
synchronized private boolean shouldClose() {
while(true) {
if (!closed) {
if (!closing) {
closing = true;
return true;
} else {
// Another thread is presently trying to close;
// wait until it finishes one way (closes
// successfully) or another (fails to close)
doWait();
}
} else
return false;
}
}

private void closeInternal(boolean waitForMerges) throws CorruptIndexException, IOException {

docWriter.pauseAllThreads();

try {
if (infoStream != null)
message("now flush at close");

docWriter.close();

// Only allow a new merge to be triggered if we are
// going to wait for merges:
if (!hitOOM) {
flush(waitForMerges, true, true);
}

if (waitForMerges)
// Give merge scheduler last chance to run, in case
// any pending merges are waiting:
mergeScheduler.merge(this);

mergePolicy.close();

finishMerges(waitForMerges);
stopMerges = true;

mergeScheduler.close();

if (infoStream != null)
message("now call final commit()");

if (!hitOOM) {
commit(0);
}

if (infoStream != null)
message("at close: " + segString());

synchronized(this) {
readerPool.close();
docWriter = null;
deleter.close();
}

if (closeDir)
directory.close();

if (writeLock != null) {
writeLock.release();                          // release write lock
writeLock = null;
}
synchronized(this) {
closed = true;
}
} catch (OutOfMemoryError oom) {
handleOOM(oom, "closeInternal");
} finally {
synchronized(this) {
closing = false;
notifyAll();
if (!closed) {
if (docWriter != null)
docWriter.resumeAllThreads();
if (infoStream != null)
message("hit exception while closing");
}
}
}
}

/** Tells the docWriter to close its currently open shared
*  doc stores (stored fields & vectors files).
*  Return value specifices whether new doc store files are compound or not.
*/
private synchronized boolean flushDocStores() throws IOException {

boolean useCompoundDocStore = false;

String docStoreSegment;

boolean success = false;
try {
docStoreSegment = docWriter.closeDocStore();
success = true;
} finally {
if (!success && infoStream != null) {
message("hit exception closing doc store segment");
}
}

useCompoundDocStore = mergePolicy.useCompoundDocStore(segmentInfos);

if (useCompoundDocStore && docStoreSegment != null && docWriter.closedFiles().size() != 0) {
// Now build compound doc store file

if (infoStream != null) {
message("create compound file " + docStoreSegment + "." + IndexFileNames.COMPOUND_FILE_STORE_EXTENSION);
}

success = false;

final int numSegments = segmentInfos.size();
final String compoundFileName = docStoreSegment + "." + IndexFileNames.COMPOUND_FILE_STORE_EXTENSION;

try {
CompoundFileWriter cfsWriter = new CompoundFileWriter(directory, compoundFileName);
final Iterator it = docWriter.closedFiles().iterator();
while(it.hasNext())
cfsWriter.addFile((String) it.next());

// Perform the merge
cfsWriter.close();
success = true;

} finally {
if (!success) {
if (infoStream != null)
message("hit exception building compound file doc store for segment " + docStoreSegment);
deleter.deleteFile(compoundFileName);
}
}

for(int i=0;i<numSegments;i++) {
SegmentInfo si = segmentInfos.info(i);
if (si.getDocStoreOffset() != -1 &&
si.getDocStoreSegment().equals(docStoreSegment))
si.setDocStoreIsCompoundFile(true);
}

checkpoint();

// In case the files we just merged into a CFS were
// not previously checkpointed:
deleter.deleteNewFiles(docWriter.closedFiles());
}

return useCompoundDocStore;
}

