SpanQuery query = (SpanQuery) c.rewrite(reader);
if (query != c) {                     // clause rewrote: must clone
if (clone == null)
clone = (SpanOrQuery) this.clone();
clone.clauses.set(i,query);
}
}
if (clone != null) {
return clone;                        // some clauses rewrote
} else {
return this;                         // no clauses rewrote
}
}

public String toString(String field) {
StringBuffer buffer = new StringBuffer();
buffer.append("spanOr([");
Iterator i = clauses.iterator();
while (i.hasNext()) {
SpanQuery clause = (SpanQuery)i.next();
buffer.append(clause.toString(field));
if (i.hasNext()) {
buffer.append(", ");
}
}
buffer.append("])");
buffer.append(ToStringUtils.boost(getBoost()));
return buffer.toString();
}

public boolean equals(Object o) {
if (this == o) return true;
if (o == null || getClass() != o.getClass()) return false;

final SpanOrQuery that = (SpanOrQuery) o;

if (!clauses.equals(that.clauses)) return false;
if (!clauses.isEmpty() && !field.equals(that.field)) return false;

return getBoost() == that.getBoost();
}

public int hashCode() {
int h = clauses.hashCode();
h ^= (h << 10) | (h >>> 23);
h ^= Float.floatToRawIntBits(getBoost());
return h;
}


private class SpanQueue extends PriorityQueue {
public SpanQueue(int size) {
initialize(size);
}

protected final boolean lessThan(Object o1, Object o2) {
Spans spans1 = (Spans)o1;
Spans spans2 = (Spans)o2;
if (spans1.doc() == spans2.doc()) {
if (spans1.start() == spans2.start()) {
return spans1.end() < spans2.end();
} else {
return spans1.start() < spans2.start();
}
} else {
return spans1.doc() < spans2.doc();
}
}
}

public Spans getSpans(final IndexReader reader) throws IOException {
if (clauses.size() == 1)                      // optimize 1-clause case
return ((SpanQuery)clauses.get(0)).getSpans(reader);

return new Spans() {
private SpanQueue queue = null;

private boolean initSpanQueue(int target) throws IOException {
queue = new SpanQueue(clauses.size());
Iterator i = clauses.iterator();
while (i.hasNext()) {
Spans spans = ((SpanQuery)i.next()).getSpans(reader);
if (   ((target == -1) && spans.next())
|| ((target != -1) && spans.skipTo(target))) {
queue.put(spans);
}
}
return queue.size() != 0;
}

public boolean next() throws IOException {
if (queue == null) {
return initSpanQueue(-1);
}

if (queue.size() == 0) { // all done
return false;
}

if (top().next()) { // move to next
queue.adjustTop();
return true;
}

queue.pop();  // exhausted a clause
return queue.size() != 0;
}

private Spans top() { return (Spans)queue.top(); }

public boolean skipTo(int target) throws IOException {
if (queue == null) {
return initSpanQueue(target);
}

boolean skipCalled = false;
while (queue.size() != 0 && top().doc() < target) {
if (top().skipTo(target)) {
queue.adjustTop();
} else {
queue.pop();
}
skipCalled = true;
}

if (skipCalled) {
return queue.size() != 0;
}
return next();
}

public int doc() { return top().doc(); }
public int start() { return top().start(); }
public int end() { return top().end(); }

// TODO: Remove warning after API has been finalized
public Collection/*<byte[]>*/ getPayload() throws IOException {
ArrayList result = null;
Spans theTop = top();
if (theTop != null && theTop.isPayloadAvailable()) {
result = new ArrayList(theTop.getPayload());
}
return result;
}

// TODO: Remove warning after API has been finalized
public boolean isPayloadAvailable() {
Spans top = top();
return top != null && top.isPayloadAvailable();
}

public String toString() {
return "spans("+SpanOrQuery.this+")@"+
((queue == null)?"START"
:(queue.size()>0?(doc()+":"+start()+"-"+end()):"END"));
}

};
}

}

