createIndex(dir2, true);

IndexReader reader1 = IndexReader.open(dir1);
assertRefCountEquals(1, reader1);

IndexReader multiReader1 = new MultiReader(new IndexReader[] {reader1, IndexReader.open(dir2)}, (mode == 0));
modifyIndex(0, dir2);
