/** Called if we hit an exception at a bad time (when
*  updating the index files) and must discard all
*  currently buffered docs.  This resets our state,
*  discarding any docs added since last flush. */
synchronized void abort() throws IOException {

try {
if (infoStream != null)
message("docWriter: now abort");

// Forcefully remove waiting ThreadStates from line
waitQueue.abort();

// Wait for all other threads to finish with
// DocumentsWriter:
pauseAllThreads();

try {

assert 0 == waitQueue.numWaiting;

waitQueue.waitingBytes = 0;

try {
abortedFiles = openFiles();
} catch (Throwable t) {
abortedFiles = null;
}

deletesInRAM.clear();

openFiles.clear();

for(int i=0;i<threadStates.length;i++)
try {
threadStates[i].consumer.abort();
} catch (Throwable t) {
}

try {
consumer.abort();
} catch (Throwable t) {
}

docStoreSegment = null;
numDocsInStore = 0;
docStoreOffset = 0;

// Reset all postings data
doAfterFlush();

} finally {
resumeAllThreads();
}
} finally {
aborting = false;
notifyAll();
}
}

/** Reset after a flush */
private void doAfterFlush() throws IOException {
// All ThreadStates should be idle when we are called
assert allThreadsIdle();
threadBindings.clear();
waitQueue.reset();
segment = null;
numDocsInRAM = 0;
nextDocID = 0;
bufferIsFull = false;
flushPending = false;
for(int i=0;i<threadStates.length;i++)
threadStates[i].doAfterFlush();
numBytesUsed = 0;
}

// Returns true if an abort is in progress
synchronized boolean pauseAllThreads() {
pauseThreads++;
while(!allThreadsIdle()) {
try {
wait();
} catch (InterruptedException ie) {
// In 3.0 we will change this to throw
// InterruptedException instead
Thread.currentThread().interrupt();
throw new RuntimeException(ie);
}
}

return aborting;
}

synchronized void resumeAllThreads() {
pauseThreads--;
assert pauseThreads >= 0;
if (0 == pauseThreads)
notifyAll();
}

private synchronized boolean allThreadsIdle() {
for(int i=0;i<threadStates.length;i++)
if (!threadStates[i].isIdle)
return false;
return true;
}

synchronized private void initFlushState(boolean onlyDocStore) {
initSegmentName(onlyDocStore);
flushState = new SegmentWriteState(this, directory, segment, docStoreSegment, numDocsInRAM, numDocsInStore, writer.getTermIndexInterval());
}

/** Flush all pending docs to a new segment */
synchronized int flush(boolean closeDocStore) throws IOException {

assert allThreadsIdle();

assert numDocsInRAM > 0;

assert nextDocID == numDocsInRAM;
assert waitQueue.numWaiting == 0;
assert waitQueue.waitingBytes == 0;

initFlushState(false);

docStoreOffset = numDocsInStore;

if (infoStream != null)
message("flush postings as segment " + flushState.segmentName + " numDocs=" + numDocsInRAM);

boolean success = false;

try {

if (closeDocStore) {
assert flushState.docStoreSegmentName != null;
assert flushState.docStoreSegmentName.equals(flushState.segmentName);
closeDocStore();
flushState.numDocsInStore = 0;
}

Collection threads = new HashSet();
for(int i=0;i<threadStates.length;i++)
threads.add(threadStates[i].consumer);
consumer.flush(threads, flushState);

if (infoStream != null) {
final long newSegmentSize = segmentSize(flushState.segmentName);
String message = "  oldRAMSize=" + numBytesUsed +
" newFlushedSize=" + newSegmentSize +
" docs/MB=" + nf.format(numDocsInRAM/(newSegmentSize/1024./1024.)) +
" new/old=" + nf.format(100.0*newSegmentSize/numBytesUsed) + "%";
message(message);
}

flushedDocCount += flushState.numDocs;

doAfterFlush();

success = true;

} finally {
if (!success) {
abort();
}
}

assert waitQueue.waitingBytes == 0;

return flushState.numDocs;
}

/** Build compound file for the segment we just flushed */
void createCompoundFile(String segment) throws IOException {

CompoundFileWriter cfsWriter = new CompoundFileWriter(directory, segment + "." + IndexFileNames.COMPOUND_FILE_EXTENSION);
Iterator it = flushState.flushedFiles.iterator();
while(it.hasNext())
cfsWriter.addFile((String) it.next());

// Perform the merge
cfsWriter.close();
}

