*  trigger a single flush even when multiple threads are
*  trying to do so. */
synchronized boolean setFlushPending() {
if (flushPending)
return false;
else {
flushPending = true;
return true;
}
}

synchronized void clearFlushPending() {
flushPending = false;
}

synchronized void pushDeletes() {
deletesFlushed.update(deletesInRAM);
