*/
public static void setUseScorer14(boolean use14) {
setAllowDocsOutOfOrder(use14);
}

/**
* @deprecated Use {@link #getAllowDocsOutOfOrder()} instead.
*/
public static boolean getUseScorer14() {
return getAllowDocsOutOfOrder();
}

public Weight createWeight(Searcher searcher) throws IOException {
return new BooleanWeight(searcher);
}

public Query rewrite(IndexReader reader) throws IOException {
if (minNrShouldMatch == 0 && clauses.size() == 1) {                    // optimize 1-clause queries
BooleanClause c = (BooleanClause)clauses.get(0);
if (!c.isProhibited()) {			  // just return clause

Query query = c.getQuery().rewrite(reader);    // rewrite first

if (getBoost() != 1.0f) {                 // incorporate boost
if (query == c.getQuery())                   // if rewrite was no-op
query = (Query)query.clone();         // then clone before boost
query.setBoost(getBoost() * query.getBoost());
}

return query;
}
}

BooleanQuery clone = null;                    // recursively rewrite
for (int i = 0 ; i < clauses.size(); i++) {
BooleanClause c = (BooleanClause)clauses.get(i);
Query query = c.getQuery().rewrite(reader);
if (query != c.getQuery()) {                     // clause rewrote: must clone
if (clone == null)
clone = (BooleanQuery)this.clone();
clone.clauses.set(i, new BooleanClause(query, c.getOccur()));
}
}
if (clone != null) {
return clone;                               // some clauses rewrote
} else
return this;                                // no clauses rewrote
}

// inherit javadoc
public void extractTerms(Set terms) {
for (Iterator i = clauses.iterator(); i.hasNext();) {
BooleanClause clause = (BooleanClause) i.next();
clause.getQuery().extractTerms(terms);
}
}

public Object clone() {
BooleanQuery clone = (BooleanQuery)super.clone();
clone.clauses = (ArrayList)this.clauses.clone();
return clone;
}

/** Prints a user-readable version of this query. */
public String toString(String field) {
StringBuffer buffer = new StringBuffer();
boolean needParens=(getBoost() != 1.0) || (getMinimumNumberShouldMatch()>0) ;
if (needParens) {
buffer.append("(");
}

for (int i = 0 ; i < clauses.size(); i++) {
BooleanClause c = (BooleanClause)clauses.get(i);
if (c.isProhibited())
buffer.append("-");
else if (c.isRequired())
buffer.append("+");

Query subQuery = c.getQuery();
if (subQuery != null) {
if (subQuery instanceof BooleanQuery) {	  // wrap sub-bools in parens
buffer.append("(");
buffer.append(subQuery.toString(field));
buffer.append(")");
} else {
buffer.append(subQuery.toString(field));
}
} else {
buffer.append("null");
}

if (i != clauses.size()-1)
buffer.append(" ");
}

if (needParens) {
buffer.append(")");
}

if (getMinimumNumberShouldMatch()>0) {
buffer.append('~');
buffer.append(getMinimumNumberShouldMatch());
}

if (getBoost() != 1.0f)
{
buffer.append(ToStringUtils.boost(getBoost()));
}

return buffer.toString();
}

/** Returns true iff <code>o</code> is equal to this. */
public boolean equals(Object o) {
if (!(o instanceof BooleanQuery))
return false;
BooleanQuery other = (BooleanQuery)o;
return (this.getBoost() == other.getBoost())
&& this.clauses.equals(other.clauses)
&& this.getMinimumNumberShouldMatch() == other.getMinimumNumberShouldMatch();
}

/** Returns a hash code value for this object.*/
public int hashCode() {
return Float.floatToIntBits(getBoost()) ^ clauses.hashCode()
+ getMinimumNumberShouldMatch();
}

}

